+// the goroutine, and if it holds a semaphore slot while suspended, other
+// tests can't proceed).
+func acquireTestSlot() { testSem <- struct{}{} }
+
+// releaseTestSlot returns a semaphore slot.
+func releaseTestSlot() { <-testSem }
+
